const repoUrl = $input.first().json.body.repoUrl || '';
const apkInfo = $input.first().json.body.apkInfo || '';

if (!repoUrl && !apkInfo) throw new Error('Forneça repositório ou APK');

let owner = '', repo = '';
if (repoUrl) {
  const match = repoUrl.match(/github\.com\/([^\/]+)\/([^\/]+)/);
  if (match) { owner = match[1]; repo = match[2].replace('.git', ''); }
}

return [{ json: { owner, repo, repoUrl, apkInfo } }];

const base = $('Extrair dados').first().json;

let manifestContent = 'Não encontrado';
let gradleContent = 'Não encontrado';

try {
  const manifestJson = $('Buscar AndroidManifest').first()?.json;
  if (manifestJson?.content) {
    manifestContent = Buffer.from(manifestJson.content, 'base64').toString('utf-8');
  }
} catch(e) {}

try {
  const gradleJson = $input.first()?.json;
  if (gradleJson?.content) {
    gradleContent = Buffer.from(gradleJson.content, 'base64').toString('utf-8');
  }
} catch(e) {}

const prompt = `Você é um especialista em Android e Google Play Store.
Analise o projeto e retorne APENAS um JSON válido com esta estrutura exata:
{
  "score": <número 0-100>,
  "summary": "<resumo em 1-2 frases>",
  "suggestions": [
    {
      "category": "<Segurança|UI/UX|Performance|Privacidade|Acessibilidade|Manifesto|Target SDK>",
      "severity": "<critical|warning|info>",
      "title": "<título curto>",
      "description": "<descrição do problema>",
      "fix": "<como corrigir>"
    }
  ]
}

Avalie: targetSdkVersion (deve ser >= 34), permissões desnecessárias, política de privacidade, ícones adaptativos, ProGuard/R8, assinatura APK, APIs obsoletas, acessibilidade.

Repositório: ${base.repoUrl}
${base.apkInfo ? 'APK: ' + base.apkInfo : ''}

=== AndroidManifest.xml ===
${manifestContent}

=== app/build.gradle ===
${gradleContent}`;

return [{ json: { prompt } }];

const response = $input.first().json;
const text = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

const jsonMatch = text.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error('Gemini não retornou JSON válido: ' + text.substring(0, 200));

const parsed = JSON.parse(jsonMatch[0]);
return [{ json: parsed }];
